    public boolean canSubmitToWorkflow()
    {
        boolean         ret             = next canSubmitToWorkflow();
        boolean         validate        = ret;
        VendBankAccount vendBankAccount = VendBankAccount_ds.cursor();
        VendTable       vendtable       = VendTable::find(vendBankAccount.VendAccount);
        DocuRef         docuref         = DocuRef::findTableIdRecId(vendBankAccount.DataAreaId,
                                                                    vendBankAccount.TableId,vendBankAccount.RecId);

        if(!docuref)
        {
            ret = checkFailed('@UBS:UBSAttachDocToBankAccount');
        }

        if(vendtable)
        {
            validate = UBSReferencingDocuments::checkReferencingDocument(vendtable.Party);

            if(validate)
            {
                DirPartyTable dirpartytable = vendtable.DirPartyTable();

                validate = UBSMandatoryDocuments::checkMandatoryDocument(vendtable.Party, dirpartytable);
            }
        }

        return ret && validate;
    }
